export class IntegrationForm {
  #bag: Record<string, unknown>;

  #common: IntegrationCommonProperties[];

  #custom?: ObjectShape;

  #extraFields: SimpleIntegrationField[];

  #formType: IntegrationFormType;

  #id: string;

  #oauth?: {
    required?: boolean;
  };

  #schema: AnyObjectSchema;

  #service: IntegrationService;

  #serviceKey: IntegrationServices;

  #serviceTitle: string;

  #supports: {
    actionPages: boolean;
    campaigns: boolean;
  };

  #values: Record<string, IntegrationFieldValue>;

  constructor({
    bag,
    common = [],
    custom,

    // set to campaigns for backwards compatibility
    // we can change this if we update the existing integration forms
    extraFields = [],

    formType = 'campaigns',
    oauth,
    serviceKey,
    serviceTitle,
    t,
    values,
  }: IntegrationFormProps) {
    this.#common = common;
    this.#custom = custom;

    this.#extraFields = extraFields;

    this.#formType = formType;
    this.#id = IntegrationForm.formId(serviceKey);

    this.#oauth = oauth;

    this.#schema = composeIntegrationFormSchema(common, {
      additionalProperties: custom,
      t,
    });

    this.#service = integrationServiceMap.get(serviceKey) as IntegrationService;
    this.#serviceKey = serviceKey;
    this.#serviceTitle = serviceTitle;

    this.#supports = {
      actionPages: this.#formType === 'actionPages',
      campaigns: this.#formType === 'campaigns',
    };

    this.#values = values || {};

    // initialize the bag
    this.#bag = bag || {};
  }

  // allow setting of bag values after construction
  bagSet(key: string, value: unknown) {
    this.#bag[key] = value;
  }

  // retrieve values from the bag
  bag(key: string) {
    if (!this.#bag || !key) {
      return undefined;
    }

    return this.#bag[key];
  }

  // context for <Form /> passed down to useForm, etc.
  context(): IntegrationFormSupports {
    return {
      actionPages: this.supports('actionPages'),
      campaigns: this.supports('campaigns'),
    };
  }

  extraFields() {
    return this.#extraFields;
  }

  // used by constructor
  // and available for determining form ID for other
  static formId(serviceKey: string) {
    return `integration-form-${serviceKey}`;
  }

  formType(): IntegrationFormType {
    return this.#formType;
  }

  #getValues() {
    const results = Object.keys(this.#values).reduce(
      (acc, k) => {
        // using this form due to eslint recommendations (no-prototype-builtins)
        // and lack of widespread browser support for `Object.hasOwn`
        if (Object.hasOwn(this.#values, k)) {
          acc[k] = this.#values![k];
        }

        return acc;
      },
      {} as Record<string, IntegrationFieldValue>
    );

    return results;
  }

  id() {
    return this.#id;
  }

  includesCommon(key: IntegrationCommonProperties) {
    // returns true if its common fields includes the key
    return this.#common.includes(key);
  }

  includesExtraField(key: IntegrationCommonProperties) {
    // returns true if extra fields includes an element
